import{_ as l,o as e,c as i,a2 as t}from"./chunks/framework.ZhLefgN8.js";const p=JSON.parse('{"title":"余额通常见问题","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/cash-plus/cash-plus-faq.md","filePath":"zh-CN/funds-and-wealth/cash-plus/cash-plus-faq.md"}'),r={name:"funds-and-wealth/cash-plus/cash-plus-faq.md"};function h(o,a,s,n,d,u){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="余额通常见问题" tabindex="-1">余额通常见问题 <a class="header-anchor" href="#余额通常见问题" aria-label="Permalink to &quot;余额通常见问题&quot;">​</a></h1><p>余额通的功能特色、手动赎回时效、收益计算方式、新股认购限制及关闭到账时间。</p><h2 id="余额通五大特色" tabindex="-1">余额通五大特色 <a class="header-anchor" href="#余额通五大特色" aria-label="Permalink to &quot;余额通五大特色&quot;">​</a></h2><ul><li>随心炒股：余额通资金可直接买入股票，无需提前赎回</li><li>闲钱增值：闲置资金自动投入货币基金，收益高于活期</li><li>一劳永逸：开通后全自动运作，无需手动操作</li><li>货基打底：以货币基金为底层资产，相对稳健</li><li>低起购：最低 0.01 起投</li></ul><h2 id="手动赎回规则" tabindex="-1">手动赎回规则 <a class="header-anchor" href="#手动赎回规则" aria-label="Permalink to &quot;手动赎回规则&quot;">​</a></h2><p>香港余额通：新版 8:30 前赎回当日处理，旧版 9:10 前赎回当日处理；超过截止时间则顺延至下一交易日。</p><ul><li>手动赎回后资金可立即用于股票交易（T+0 可用）</li><li>手动赎回后 3 个自然日内不会触发自动转入</li></ul><h2 id="货币兑换与出金限制" tabindex="-1">货币兑换与出金限制 <a class="header-anchor" href="#货币兑换与出金限制" aria-label="Permalink to &quot;货币兑换与出金限制&quot;">​</a></h2><ul><li>需先手动赎回并等待资金到账，之后才能进行换汇或出金操作</li><li>不支持在余额通赎回过程中直接换汇或出金</li></ul><h2 id="新股认购限制" tabindex="-1">新股认购限制 <a class="header-anchor" href="#新股认购限制" aria-label="Permalink to &quot;新股认购限制&quot;">​</a></h2><ul><li>若账户资金在余额通中，需在新股截止认购日的前一交易日 9:30 前完成申购（确保资金及时到位）</li><li>建议提前确认资金状态，避免因赎回时间不足导致认购失败</li></ul><h2 id="转仓费用支付" tabindex="-1">转仓费用支付 <a class="header-anchor" href="#转仓费用支付" aria-label="Permalink to &quot;转仓费用支付&quot;">​</a></h2><p>暂不支持使用余额通资金直接支付转仓费用，需提前将资金赎回至普通账户。</p><h2 id="收益计算" tabindex="-1">收益计算 <a class="header-anchor" href="#收益计算" aria-label="Permalink to &quot;收益计算&quot;">​</a></h2><p>当前 7 日年化利率见上方实时数据。</p><ul><li>新版香港余额通：每天 8:30 计算当日收益</li><li>旧版香港余额通：每天 9:10 计算当日收益</li><li>示例：持有 1 万港元，7 日年化 3%，每日收益约 = 10000 × 3% ÷ 365 ≈ 0.82 港元</li></ul><h2 id="关闭后到账时间" tabindex="-1">关闭后到账时间 <a class="header-anchor" href="#关闭后到账时间" aria-label="Permalink to &quot;关闭后到账时间&quot;">​</a></h2><p>关闭后系统在最近交易日发起赎回，最晚 T+1 个交易日到账。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth/余额通交易规则">余额通交易规则</a> — 交易规则与时间限制</li></ul>',20)])])}const f=l(r,[["render",h]]);export{p as __pageData,f as default};
